const item = $input.first();
const form = $('On form submission').first().json;
const raw = String(form.searchStringsArray || '').trim();
const terms = raw.split(',').map(s => s.trim()).filter(Boolean);
item.json = {
  vertical: String(form.vertical || '').trim().toLowerCase(),
  search_terms: terms,
  location_query: String(form.locationQuery || '').trim(),
  max_per_search: Number(form.maxCrawledPlacesPerSearch || 0),
  WEBHOOK_BASE: item.json.WEBHOOK_BASE,
  APIFY_ACTOR_ID: item.json.APIFY_ACTOR_ID,
};
return [item];

