// Apify registers ad-hoc webhooks from a base64-encoded `webhooks` query param on
// the run POST (not from the actor-input body). Apify interpolates {{resource.*}}
// only when the placeholder is UNQUOTED, so it substitutes the JSON-stringified
// value (quotes included). run_pk / vertical are our own values, so we inline them.
const item = $input.first().json;
const base = $('Parse form').first().json.WEBHOOK_BASE;
const webhooks = [{
  eventTypes: ['ACTOR.RUN.SUCCEEDED', 'ACTOR.RUN.FAILED', 'ACTOR.RUN.ABORTED', 'ACTOR.RUN.TIMED_OUT'],
  requestUrl: base + '/webhook/maps-lead-enrich-inbound',
  payloadTemplate: '{"run_pk": ' + item.id + ', "vertical": "' + item.vertical + '", "apify_run_id": {{resource.id}}, "dataset_id": {{resource.defaultDatasetId}}, "status": {{resource.status}}}'
}];
return [{ json: { id: item.id, vertical: item.vertical, webhooksB64: Buffer.from(JSON.stringify(webhooks)).toString('base64') } }];

